import { useState } from 'react';
import {
  Button,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogContentText,
  DialogTitle,
  TextField,
  InputAdornment,
  Box,
  Typography,
} from '@mui/material';
import { toast } from 'react-toastify';

import { abrirSessao } from '../services/sessaoService';
import type { PautaDetalhadaRespostaDTO } from '../types';

const formatarDataHora = (dataString: string | undefined | null) => {
  if (!dataString) return '--';
  const data = new Date(dataString);
  return new Intl.DateTimeFormat('pt-BR', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  }).format(data);
};

interface ModalAbrirSessaoProps {

  pauta: PautaDetalhadaRespostaDTO | null;

  aberto: boolean;

  aoFechar: () => void;

  aoSucesso: () => void;
}

const ModalAbrirSessao = ({ pauta, aberto, aoFechar, aoSucesso }: ModalAbrirSessaoProps) => {
  const [tempo, setTempo] = useState<string>('1');
  const [salvando, setSalvando] = useState(false);

  const calcularPrevisao = () => {
    let tempoNumerico = parseInt(tempo, 10);
    if (isNaN(tempoNumerico) || tempoNumerico <= 0) tempoNumerico = 1;

    const agora = new Date();
    agora.setMinutes(agora.getMinutes() + tempoNumerico);
    return formatarDataHora(agora.toISOString());
  };

  const limparFormulario = () => {
    setTempo('1');
  };

  const fechar = () => {
    if (salvando) return;
    limparFormulario();
    aoFechar();
  };

  const aoSubmeter = async () => {
    if (!pauta?.id) return;

    let tempoNumerico = parseInt(tempo, 10);
    if (isNaN(tempoNumerico) || tempoNumerico <= 0) {
      tempoNumerico = 1; 
    }

    setSalvando(true);

    try {
      await abrirSessao({
        pautaId: pauta.id,
        tempoEmMinutos: tempoNumerico,
      });

      toast.success('Sess├úo de vota├º├úo aberta com sucesso!');
      limparFormulario();
      aoSucesso();
      aoFechar();
    } catch {

    } finally {
      setSalvando(false);
    }
  };

  return (
    <Dialog
      open={aberto}
      onClose={fechar}
      fullWidth
      maxWidth="sm"
      PaperProps={{ sx: { borderRadius: 3 } }}
    >
      <DialogTitle sx={{ fontWeight: 700, pb: 1 }}>
        Abrir Sess├úo de Vota├º├úo
      </DialogTitle>

      <DialogContent sx={{ display: 'flex', flexDirection: 'column', gap: 3, pt: 1 }}>
        <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap', bgcolor: '#f8fafc', p: 1.5, borderRadius: 2, border: '1px solid #e2e8f0' }}>
          <Box>
            <Typography variant="caption" color="text.secondary" fontWeight={600} display="block">Pauta Criada em</Typography>
            <Typography variant="caption" fontWeight={700} color="text.primary">{formatarDataHora(pauta?.dataHoraCriacao)}</Typography>
          </Box>
          <Box sx={{ ml: 'auto', textAlign: 'right' }}>
            <Typography variant="caption" color="primary" fontWeight={600} display="block">Previs├úo de Encerramento</Typography>
            <Typography variant="body2" fontWeight={800} color="primary.main">{calcularPrevisao()}</Typography>
          </Box>
        </Box>

        <DialogContentText sx={{ mb: 1 }}>
          Defina o tempo de dura├º├úo da sess├úo de vota├º├úo. Se deixar em branco ou zero, ser├í assumido o tempo padr├úo de 1 minuto.
        </DialogContentText>

        <TextField
          label="Dura├º├úo da Sess├úo"
          type="number"
          value={tempo}
          onChange={(e) => setTempo(e.target.value)}
          fullWidth
          autoFocus
          InputProps={{
            endAdornment: <InputAdornment position="end">minutos</InputAdornment>,
            inputProps: { min: 1, max: 1440 }
          }}
        />
      </DialogContent>

      <DialogActions sx={{ px: 3, pb: 2 }}>
        <Button onClick={fechar} disabled={salvando} color="inherit">
          Cancelar
        </Button>
        <Button
          onClick={aoSubmeter}
          variant="contained"
          color="primary"
          disabled={salvando}
          startIcon={salvando ? <CircularProgress size={18} color="inherit" /> : null}
        >
          {salvando ? 'Abrindo...' : 'Abrir Sess├úo'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default ModalAbrirSessao;

import { useState } from 'react';
import {
  Button,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  TextField,
} from '@mui/material';
import { toast } from 'react-toastify';

import { criarPauta } from '../services/pautaService';

interface ModalNovaPautaProps {

  aberto: boolean;

  aoFechar: () => void;

  aoSucesso: () => void;
}

const TITULO_MIN = 3;
const TITULO_MAX = 255;
const DESCRICAO_MAX = 2000;

const ModalNovaPauta = ({ aberto, aoFechar, aoSucesso }: ModalNovaPautaProps) => {
  const [titulo, setTitulo] = useState('');
  const [descricao, setDescricao] = useState('');
  const [salvando, setSalvando] = useState(false);
  const [erroTitulo, setErroTitulo] = useState('');

  const limparFormulario = () => {
    setTitulo('');
    setDescricao('');
    setErroTitulo('');
  };

  const fechar = () => {
    if (salvando) return; 
    limparFormulario();
    aoFechar();
  };

  const validar = (): boolean => {
    const tituloTrimado = titulo.trim();

    if (tituloTrimado.length < TITULO_MIN) {
      setErroTitulo(`O t├¡tulo deve ter pelo menos ${TITULO_MIN} caracteres.`);
      return false;
    }

    if (tituloTrimado.length > TITULO_MAX) {
      setErroTitulo(`O t├¡tulo deve ter no m├íximo ${TITULO_MAX} caracteres.`);
      return false;
    }

    setErroTitulo('');
    return true;
  };

  const aoSubmeter = async () => {
    if (!validar()) return;

    setSalvando(true);

    try {
      await criarPauta({
        titulo: titulo.trim(),
        descricao: descricao.trim() || undefined,
      });

      toast.success('Pauta criada com sucesso!');
      limparFormulario();
      aoSucesso();
      aoFechar();
    } catch {

    } finally {
      setSalvando(false);
    }
  };

  return (
    <Dialog
      open={aberto}
      onClose={fechar}
      fullWidth
      maxWidth="sm"
      PaperProps={{ sx: { borderRadius: 3 } }}
    >
      <DialogTitle sx={{ fontWeight: 700, pb: 1 }}>
        Nova Pauta
      </DialogTitle>

      <DialogContent sx={{ display: 'flex', flexDirection: 'column', gap: 2, pt: 1 }}>
        <TextField
          label="T├¡tulo"
          placeholder="Ex: Aprova├º├úo do or├ºamento anual"
          value={titulo}
          onChange={(e) => {
            setTitulo(e.target.value);
            if (erroTitulo) setErroTitulo('');
          }}
          error={!!erroTitulo}
          helperText={erroTitulo || `${titulo.length}/${TITULO_MAX} caracteres`}
          inputProps={{ maxLength: TITULO_MAX }}
          required
          fullWidth
          autoFocus
          sx={{ mt: 1 }}
        />

        <TextField
          label="Descri├º├úo (opcional)"
          placeholder="Descreva o contexto da pauta..."
          value={descricao}
          onChange={(e) => setDescricao(e.target.value)}
          helperText={`${descricao.length}/${DESCRICAO_MAX} caracteres`}
          inputProps={{ maxLength: DESCRICAO_MAX }}
          multiline
          rows={3}
          fullWidth
        />
      </DialogContent>

      <DialogActions sx={{ px: 3, pb: 2 }}>
        <Button onClick={fechar} disabled={salvando} color="inherit">
          Cancelar
        </Button>
        <Button
          onClick={aoSubmeter}
          variant="contained"
          disabled={salvando}
          startIcon={salvando ? <CircularProgress size={18} color="inherit" /> : null}
        >
          {salvando ? 'Salvando...' : 'Salvar'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default ModalNovaPauta;

import 'recharts';

declare module 'recharts' {
  interface PieProps {
    activeIndex?: number | number[];

    activeShape?: ((props: any) => React.ReactElement) | React.ReactElement;
  }
}
